+        }
+    } else {
+        0
+    };
+    let stored = stored_lo | (stored_hi << 16);
+
+    if csum != stored {
+        return Err(ParseError::InvalidField {
+            field: "i_checksum",
+            reason: "inode CRC32C mismatch",
+        });
+    }
+    Ok(())
+}
