+        //   Block 0: boot + superblock (offset 1024..2048)
+        //   Block 1: group descriptor table
+        //   Block 2: inode table (8192 inodes * 256 bytes, but we only populate a few)
+        let block_size = 4096_usize;
+        let image_blocks = 32; // 128K image
